PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?matchDate WHERE {
  {
    ?match wdt:P199 wd:Q185295 ; wdt:P644 wd:Q3732909 ; wdt:P128 ?homeScore ; wdt:P129 ?awayScore ; wdt:P585 ?matchDate .
    FILTER(xsd:integer(?homeScore) > xsd:integer(?awayScore))
    FILTER(isNumeric(?homeScore) && isNumeric(?awayScore))
  } UNION {
    ?match wdt:P199 wd:Q185295 ; wdt:P645 wd:Q3732909 ; wdt:P128 ?awayScore ; wdt:P129 ?homeScore ; wdt:P585 ?matchDate .
    FILTER(xsd:integer(?awayScore) > xsd:integer(?homeScore))
    FILTER(isNumeric(?awayScore) && isNumeric(?homeScore))
  }
}
ORDER BY DESC(?matchDate)
LIMIT 1

